		return {
			ok: false,
			error: "Could not determine whether Codex created a commit.",
			commands: { commit_count: commitCountCommand },
		};
	}

	if (commitCount < 1) {
			return {
				ok: false,
				error: "Codex did not create a commit beyond origin/" + baseBranch + ".",
				commands: { commit_count: commitCountCommand },
			};
	}

