				push: pushCommand,
				verify: verifyCommand,
			},
		};
	}

	return {
		ok: true,
		error: null,
		commands: {
			commit_count: commitCountCommand,
			push: pushCommand,
			verify: verifyCommand,
		},
		pr_spec: prSpecResult.value,
	};
}

