		const summary = evaluateRule(patterns, changedFiles);

		if (summary.matched.length > 0 && summary.unmatched.length > 0) {
			return {
				action: "auto_merge_candidate",
				reason: `Auto-merge policy matched rule ${ruleIndex} with mixed file coverage; unmatched files will still be reviewed.",
				ruleIndex,
				rulePatterns: patterns,
				changedPathsSummary: summary,
				policyConfigured,
			};
		}

		if (summary.matched.length > 0 && summary.unmatched.length === 0) {
			return {
				action: "auto_merge_candidate",
				reason: `Auto-merge policy matched rule ${ruleIndex} for all changed paths.`,
				ruleIndex,
				rulePatterns: patterns,
				changedPathsSummary: summary,
				policyConfigured,
			};
		}
	}

