function evaluateRule(patterns: string[], changedPaths: string[]): MatchedPathsSummary {
	const normalizedPatterns = patterns.map((pattern) => normalizePathPattern(pattern));
	const summary: MatchedPathsSummary = { excluded: [], matched: [], unmatched: [] };

	for (const changedPath of changedPaths) {
		const normalizedPath = changedPath.replace(/^\.\/+/, "");
		let isMatched = false;
		let lastMatchedValue = false;
		let wasExplicitlyExcluded = false;

		for (const pattern of normalizedPatterns) {
			if (pattern.patternType === "exclude" && pattern.value.length === 0) {
				continue;
			}

			if (matchGlob(normalizedPath, pattern.value)) {
				isMatched = true;
				lastMatchedValue = pattern.patternType === "include";
				if (pattern.patternType === "exclude") {
					wasExplicitlyExcluded = true;
				}
			}
		}

		if (isMatched && lastMatchedValue) {
			summary.matched.push(normalizedPath);
			continue;
		}

		if (wasExplicitlyExcluded) {
			summary.excluded.push(normalizedPath);
			continue;
		}

		summary.unmatched.push(normalizedPath);
	}

	return summary;
}

type NormalizedPattern = {
	patternType: "include" | "exclude";
	value: string;
};

function normalizePathPattern(pattern: string): NormalizedPattern {
	const trimmed = pattern.trim();
	if (trimmed.startsWith("!")) {
		return { patternType: "exclude", value: trimmed.slice(1).trim() };
	}

	return { patternType: "include", value: trimmed };
}

function matchGlob(filePath: string, pattern: string): boolean {
	const regexSource = "^" + globToRegex(pattern) + "$";
	return new RegExp(regexSource).test(filePath);
}

function globToRegex(pattern: string): string {
	let i = 0;
	let output = "";

	while (i < pattern.length) {
		const char = pattern[i];
		if (char === "*") {
			if (pattern[i + 1] === "*" && pattern[i + 2] === "/") {
				output += "(.*/)?";
				i += 2;
				continue;
			}
			if (pattern[i + 1] === "*") {
				output += ".*";
				i += 2;
				continue;
			}
			output += "[^/]*";
			i += 1;
			continue;
		}

		if (char === "?") {
			output += "[^/]";
			i += 1;
			continue;
		}

		if ("+^$.()|{}[]\\".includes(char)) {
			output += `\\${char}`;
			i += 1;
			continue;
		}

		output += char;
		i += 1;
	}

	return output;
}

