import { readFile } from "node:fs/promises";
import path from "node:path";

const RHAPSODY_POST_RUN_CONFIG_PATH = ".rhapsody/config.toml";

export type PostRunDecisionPolicy = {
	auto_merge_eligible: PostRunAutoMergeRule[];
};

export type PostRunAutoMergeRule = {
	patterns: string[];
	excludes?: string[];
	description?: string;
};

export type PostRunDecisionConfig = {
	post_run: PostRunDecisionPolicy;
};

export type PostRunPolicyLoadResult = {
	config: PostRunDecisionConfig;
	loadedFromPath: string;
	errors: string[];
};

export type PostRunDecisionInput = {
	runStatus: string;
	attemptStatus: string;
	handoffStatus: "ok" | "not_applicable" | "missing_pr" | "failed";
	changedFiles: string[] | null;
	config: PostRunDecisionConfig;
};

export type MatchedPathsSummary = {
	excluded: string[];
	matched: string[];
	unmatched: string[];
};

export type PostRunDecision = {
	action: "auto_merge_candidate" | "human_review";
	reason: string;
	ruleIndex: number | null;
	rulePatterns: string[] | null;
	ruleExcludes: string[] | null;
	matchedPatterns: string[];
	changedPathsSummary: MatchedPathsSummary;
	policyConfigured: boolean;
};

export class PostRunPolicyError extends Error {
	constructor(readonly issues: string[]) {
		super(`Invalid post-run decision policy:\n${issues.map((issue) => `- ${issue}`).join("\n")}`);
		this.name = "PostRunPolicyError";
	}
}

export async function loadPostRunDecisionConfig(
	projectRoot = process.cwd(),
): Promise<PostRunPolicyLoadResult> {
	const configPath = path.join(projectRoot, RHAPSODY_POST_RUN_CONFIG_PATH);
	const errors: string[] = [];

	try {
		const rawConfig = await readFile(configPath, "utf8");
		const config = parsePostRunDecisionConfig(rawConfig);
		validatePostRunDecisionConfig(config);
		return { config, loadedFromPath: configPath, errors };
	} catch (error) {
		if (error instanceof PostRunPolicyError) {
			throw error;
		}

		if (error instanceof Error && (error as NodeJS.ErrnoException).code === "ENOENT") {
			return {
				config: { post_run: { auto_merge_eligible: [] } },
				loadedFromPath: configPath,
				errors: ["Post-run decision config file is missing; defaulting to conservative review-required policy."],
			};
		}

		throw error;
	}
}

export function parsePostRunDecisionConfig(content: string): PostRunDecisionConfig {
	const lines = content.split(/\r?\n/);
	const config: PostRunDecisionConfig = { post_run: { auto_merge_eligible: [] } };

	let inPostRunSection = false;
	let inAutoMergeRuleSection = false;
	let currentRule: Partial<PostRunAutoMergeRule> | null = null;

	for (const rawLine of lines) {
		const trimmed = stripComment(rawLine).trim();

		if (!trimmed) {
			continue;
		}

		if (trimmed === "[post_run]") {
			inPostRunSection = true;
			inAutoMergeRuleSection = false;
			currentRule = null;
			continue;
		}

		if (trimmed === "[[post_run.auto_merge_eligible]]") {
			inPostMergeAutoMergeEligibleSection(inPostRunSection);
			inAutoMergeRuleSection = true;
			currentRule = { patterns: [], excludes: [], description: "" };
			config.post_run.auto_merge_eligible.push({
				patterns: [],
				excludes: [],
			});
			continue;
		}

		if (trimmed.startsWith("[[") || trimmed.startsWith("[")) {
			inAutoMergeRuleSection = false;
			currentRule = null;
			continue;
		}

		if (!inPostRunSection) {
			continue;
		}

		if (!inAutoMergeRuleSection) {
			continue;
		}

		if (!currentRule) {
			throw new PostRunPolicyError(["Invalid TOML structure: field found outside of rule table."]);
		}

		const assignResult = parseKeyValue(trimmed);

		if (!assignResult.ok) {
			throw new PostRunPolicyError([assignResult.error]);
		}

		const rule = config.post_run.auto_merge_eligible[
			config.post_run.auto_merge_eligible.length - 1
		];

		switch (assignResult.key) {
			case "paths": {
				const values = parseStringArray(assignResult.value);
				rule.paths = values;
				break;
			}
			case "excludes": {
				const values = parseStringArray(assignResult.value);
				rule.excludes = values;
				break;
			}
			case "description":
				rule.description = assignResult.value;
				break;
			default:
				throw new PostRunPolicyError([
					`Unknown field '${assignResult.key}' in auto merge rule.`,
				]);
		}
	}

	for (const rule of config.post_run.auto_merge_eligible) {
		rule.excludes ??= [];
	}

	return config;
}

function inPostMergeAutoMergeEligibleSection(inPostRunSection: boolean) {
	if (!inPostRunSection) {
		throw new PostRunPolicyError([
			"[[post_run.auto_merge_eligible]] must appear inside a [post_run] section.",
		]);
	}
}

function stripComment(input: string): string {
	let inQuotes = false;
	let escaped = false;
	let output = "";

	for (const char of input) {
		if (!inQuotes && char === "#") {
			break;
		}

		if (char === "\\") {
			escaped = !escaped;
			output += char;
			continue;
		}

		if (!escaped && char === '"') {
			inQuotes = !inQuotes;
		}

		output += char;
		escaped = false;
	}

	return output;
}

function parseKeyValue(line: string): { ok: true; key: string; value: string } | { ok: false; error: string } {
	const keyValue = line.split("=", 2);

	if (keyValue.length !== 2) {
		return { ok: false, error: `Malformed TOML key/value pair: ${line}` };
	}

	const key = keyValue[0]?.trim();
	const value = keyValue[1]?.trim();

	if (!key || !value) {
		return { ok: false, error: `Malformed TOML key/value pair: ${line}` };
	}

	return { ok: true, key, value };
}

function parseStringArray(input: string): string[] {
	const match = /^\[(.*)\]$/.exec(input);

	if (!match || !match[1]) {
		throw new PostRunPolicyError([`Expected a string array, got '${input}'.`]);
	}

	const items = splitCsvTopLevel(match[1]);
	const values = items.map((rawItem) => {
		const value = rawItem.trim();

		if (!value.startsWith('"') || !value.endsWith('"') || value.length < 2) {
			throw new PostRunPolicyError([`Expected quoted string in array, got '${value}'.`]);
		}

		return decodeTomlString(value);
	});

	return values;
}

function decodeTomlString(value: string): string {
	return JSON.parse(value);
}

function splitCsvTopLevel(input: string): string[] {
	const items: string[] = [];
	let inQuotes = false;
	let current = "";
	let escaped = false;

	for (const char of input) {
		if (char === "," && !inQuotes) {
			if (current.trim()) {
				items.push(current.trim());
			}
			current = "";
			continue;
		}

		if (char === '"') {
			if (!escaped) {
				inQuotes = !inQuotes;
			}
			escaped = false;
			current += char;
			continue;
		}

		if (char === "\\") {
			escaped = !escaped;
			current += char;
			continue;
		}

		current += char;
		escaped = false;
	}

	if (current.trim()) {
		items.push(current.trim());
	}

	return items.filter((item) => item.length > 0);
}

function validatePostRunDecisionConfig(config: PostRunDecisionConfig) {
	const issues: string[] = [];

	if (!Array.isArray(config.post_run.auto_merge_eligible)) {
		issues.push("post_run.auto_merge_eligible must be an array.");
	}

	for (const [index, rule] of config.post_run.auto_merge_eligible.entries()) {
		if (!Array.isArray(rule.patterns) || rule.patterns.length === 0) {
			issues.push(`post_run.auto_merge_eligible[${index}].patterns must be a non-empty array.`);
			continue;
		}

		if (!rule.patterns.every((pattern) => typeof pattern === "string" && pattern.trim())) {
			issues.push(`post_run.auto_merge_eligible[${index}].patterns must contain only non-empty strings.`);
		}

		if (rule.excludes && !Array.isArray(rule.excludes)) {
			issues.push(`post_run.auto_merge_eligible[${index}].excludes must be an array if provided.`);
		}

		if (rule.excludes?.some((exclude) => typeof exclude !== "string" || !exclude.trim())) {
			issues.push(`post_run.auto_merge_eligible[${index}].excludes must contain only non-empty strings.`);
		}
	}

	if (issues.length > 0) {
		throw new PostRunPolicyError(issues);
	}
}

export function evaluatePostRunDecision(input: PostRunDecisionInput): PostRunDecision {
	const { runStatus, attemptStatus, handoffStatus, changedFiles, config } = input;
	const policyConfigured = config.post_run.auto_merge_eligible.length > 0;

	if (runStatus !== "completed" || attemptStatus !== "completed") {
		return {
			action: "human_review",
			reason: `Conservative default retained: terminal status was ${runStatus}/${attemptStatus}, not eligible for auto-merge.`,
			ruleIndex: null,
			rulePatterns: null,
			ruleExcludes: null,
			matchedPatterns: [],
			changedPathsSummary: {
				excluded: [],
				matched: [],
				unmatched: changedFiles ?? [],
			},
			policyConfigured,
		};
	}

	if (handoffStatus !== "ok") {
		return {
			action: "human_review",
			reason:
				handoffStatus === "missing_pr"
					? "No pull request was produced by handoff, so review is required."
					: `Post-run handoff was not completed successfully: ${handoffStatus}.`,
			ruleIndex: null,
			rulePatterns: null,
			ruleExcludes: null,
			matchedPatterns: [],
			changedPathsSummary: {
				excluded: [],
				matched: [],
				unmatched: changedFiles ?? [],
			},
			policyConfigured,
		};
	}

	if (!Array.isArray(changedFiles) || changedFiles.length === 0) {
		return {
			action: "human_review",
			reason:
				"No changed file list was available from runner postflight; auto-merge is intentionally disabled.",
			ruleIndex: null,
			rulePatterns: null,
			ruleExcludes: null,
			matchedPatterns: [],
			changedPathsSummary: { excluded: [], matched: [], unmatched: [] },
			policyConfigured,
		};
	}

	for (let ruleIndex = 0; ruleIndex < config.post_run.auto_merge_eligible.length; ruleIndex += 1) {
		const rule = config.post_run.auto_merge_eligible[ruleIndex];
		const patterns = normalizeRulePatterns(rule.patterns, rule.excludes);
		const summary = evaluateRule(patterns, changedFiles);

		if (summary.matched.length > 0 && summary.unmatched.length === 0) {
			return {
				action: "auto_merge_candidate",
				reason: `Auto-merge policy matched rule ${ruleIndex}; all changed paths were eligible.`,
				ruleIndex,
				rulePatterns: rule.patterns,
				ruleExcludes: rule.excludes ?? null,
				matchedPatterns: rule.patterns.filter((pattern) => !pattern.startsWith("!")),
				changedPathsSummary: summary,
				policyConfigured,
			};
		}

		// Any unmatched path means the rule does not provide an eligible auto-merge candidate.
	}

	return {
		action: "human_review",
		reason: "No auto-merge policy rule matched all changed paths.",
		ruleIndex: null,
		rulePatterns: null,
		ruleExcludes: null,
		matchedPatterns: [],
		changedPathsSummary: {
			excluded: [],
			matched: [],
			unmatched: changedFiles,
		},
		policyConfigured,
	};
}

function evaluateRule(patterns: string[], changedPaths: string[]): MatchedPathsSummary {
	const normalizedPatterns = patterns.map((pattern) => normalizePathPattern(pattern));
	const summary: MatchedPathsSummary = { excluded: [], matched: [], unmatched: [] };

	for (const changedPath of changedPaths) {
		const normalizedPath = changedPath.replace(/^\.\/+/, "");
