		}

		if (isMatched && lastMatchedValue) {
			summary.matched.push(normalizedPath);
			continue;
		}

		if (wasExplicitlyExcluded) {
			summary.excluded.push(normalizedPath);
			continue;
		}

		summary.unmatched.push(normalizedPath);
	}

	return summary;
}

type NormalizedPattern = {
	patternType: "include" | "exclude";
	value: string;
};

function normalizePathPattern(pattern: string): NormalizedPattern {
	const trimmed = pattern.trim();
	return trimmed.startsWith("!")
		? { patternType: "exclude", value: trimmed.slice(1).trim() }

