type RuleMatchSummary = {
	isMatch: boolean;
	matched: string[];
	unmatched: string[];
	excluded: string[];
	missingRequiredPatterns: string[];
};

function evaluateRule(
	rule: PostRunAutoMergeRule,
	changedPaths: string[],
): RuleMatchSummary {
	const includes = splitRulePatterns(rule.paths, rule.excludes);
	const normalizedIncludes = includes.include.map((pattern) =>
		normalizePathPattern(pattern),
	);
	const normalizedExcludes = includes.exclude.map((pattern) =>
		normalizePathPattern(pattern),
	);
	const matchedRequiredPatterns = new Set<string>();
	const requiredPatterns = new Set(
		normalizedIncludes
			.filter((pattern) => pattern.patternType === "include")
			.map((pattern) => pattern.value),
	);
	const summary = {
		excluded: [],
		matched: [],
		unmatched: [],
		missingRequiredPatterns: Array.from(requiredPatterns),
		isMatch: false,
	};

