			summary.missingRequiredPatterns = summary.missingRequiredPatterns.filter(
				(value) => value !== pattern,
			);
		}
	}

	summary.isMatch =
		summary.missingRequiredPatterns.length === 0 &&
		summary.unmatched.length === 0 &&
		summary.matched.length > 0;

	return summary;
