type RuleMatchSummary = {
	isMatch: boolean;
	matched: string[];
	unmatched: string[];
	excluded: string[];
	missingRequiredPatterns: string[];
};

function evaluateRule(
	rule: PostRunAutoMergeRule,
	changedPaths: string[],
): RuleMatchSummary {
	const includes = splitRulePatterns(rule.paths, rule.excludes);
	const normalizedIncludes = includes.include.map((pattern) =>
		normalizePathPattern(pattern),
	);
	const normalizedExcludes = includes.exclude.map((pattern) =>
		normalizePathPattern(pattern),
	);
	const matchedRequiredPatterns = new Set<string>();
	const requiredPatterns = new Set(
		normalizedIncludes
			.filter((pattern) => pattern.patternType === "include")
			.map((pattern) => pattern.value),
	);
	const summary = {
		excluded: [],
		matched: [],
		unmatched: [],
		missingRequiredPatterns: Array.from(requiredPatterns),
		isMatch: false,
	};

	for (const changedPath of changedPaths) {
		const normalizedPath = changedPath.replace(/^\.\/+/, "");
		let isIncluded = false;
		let isExplicitlyExcluded = false;

		for (const pattern of normalizedIncludes) {
			if (matchGlob(normalizedPath, pattern.value)) {
				isIncluded = true;
				matchedRequiredPatterns.add(pattern.value);
			}
		}

		for (const pattern of normalizedExcludes) {
			if (matchGlob(normalizedPath, pattern.value)) {
				isExplicitlyExcluded = true;
			}
		}

		if (isExplicitlyExcluded) {
			summary.excluded.push(normalizedPath);
			continue;
		}

		if (isIncluded) {
			summary.matched.push(normalizedPath);
			continue;
		}

		summary.unmatched.push(normalizedPath);
	}

	const missingRequiredPatterns = summary.missingRequiredPatterns.filter(
		(pattern) => !matchedRequiredPatterns.has(pattern),
	);
	summary.isMatch =
		missingRequiredPatterns.length === 0 &&
		summary.unmatched.length === 0 &&
		summary.excluded.length === 0 &&
		summary.matched.length > 0;
	summary.missingRequiredPatterns = missingRequiredPatterns;

	return summary;
}

type NormalizedPattern = {
	patternType: "include" | "exclude";
	value: string;
};

function normalizePathPattern(pattern: string): NormalizedPattern {
	const trimmed = pattern.trim();
	return trimmed.startsWith("!")
		? { patternType: "exclude", value: trimmed.slice(1).trim() }
		: { patternType: "include", value: trimmed };
}

function matchGlob(filePath: string, pattern: string): boolean {
	const regexSource = "^" + globToRegex(pattern) + "$";
	return new RegExp(regexSource).test(filePath);
}

type RulePatternGroups = {
	include: string[];
	exclude: string[];
};

function splitRulePatterns(
	includes: string[],
	excludes?: string[],
): RulePatternGroups {
	const includePatterns = includes.filter((pattern) => pattern.trim());
	const normalizedIncludes = includePatterns.map((pattern) => pattern.trim());
	const normalizedExcludes = excludes
		?.map((pattern) =>
			pattern.trim().startsWith("!")
				? pattern.trim().slice(1).trim()
				: pattern.trim(),
		)
		?.filter((pattern) => pattern.length > 0);

	return {
		include: normalizedIncludes,
		exclude: normalizedExcludes ?? [],
	};
}

function globToRegex(pattern: string): string {
	let i = 0;
	let output = "";

	while (i < pattern.length) {
		const char = pattern[i];
		if (char === "*") {
			if (pattern[i + 1] === "*") {
				output += ".*";
				i += 2;
				continue;
			}
			output += "[^/]*";
			i += 1;
			continue;
		}

		if (char === "?") {
			output += "[^/]";
			i += 1;
			continue;
		}

		if ("+^$.()|{}[]\\".includes(char)) {
			output += `\\${char}`;
			i += 1;
			continue;
		}

		output += char;
		i += 1;
	}

	return output;
}
