}

export function evaluatePostRunDecision(
	input: PostRunDecisionInput,
): PostRunDecision {
	const { runStatus, attemptStatus, handoffStatus, changedFiles, config } =
		input;
	const policyConfigured = config.post_run.auto_merge_eligible.length > 0;

	if (runStatus !== "completed" || attemptStatus !== "completed") {
		return {
			action: "human_review",
			reason: `Conservative default retained: terminal status was ${runStatus}/${attemptStatus}, not eligible for auto-merge.`,
			ruleIndex: null,
			rulePatterns: null,
			ruleExcludes: null,
			matchedPatterns: [],
			changedPathsSummary: {
				excluded: [],
				matched: [],
				unmatched: changedFiles ?? [],
			},
			policyConfigured,
		};
	}

	if (handoffStatus !== "ok") {
		return {
			action: "human_review",
			reason:
				handoffStatus === "missing_pr"
					? "No pull request was produced by handoff, so review is required."
					: `Post-run handoff was not completed successfully: ${handoffStatus}.`,
			ruleIndex: null,
			rulePatterns: null,
			ruleExcludes: null,
			matchedPatterns: [],
			changedPathsSummary: {
				excluded: [],
				matched: [],
				unmatched: changedFiles ?? [],
			},
			policyConfigured,
		};
	}

	if (!Array.isArray(changedFiles) || changedFiles.length === 0) {
		return {
			action: "human_review",
			reason:
				"No changed file list was available from runner postflight; auto-merge is intentionally disabled.",
			ruleIndex: null,
			rulePatterns: null,
			ruleExcludes: null,
			matchedPatterns: [],
			changedPathsSummary: { excluded: [], matched: [], unmatched: [] },
			policyConfigured,
		};
	}

	for (
		let ruleIndex = 0;
		ruleIndex < config.post_run.auto_merge_eligible.length;
		ruleIndex += 1
	) {
		const rule = config.post_run.auto_merge_eligible[ruleIndex];
		const summary = evaluateRule(rule, changedFiles);

		if (summary.isMatch) {
			return {
				action: "auto_merge_candidate",
				reason: `Auto-merge policy matched rule ${ruleIndex}; all changed paths were eligible.`,
				ruleIndex,
				rulePatterns: rule.paths,
				ruleExcludes: rule.excludes ?? null,
				matchedPatterns: rule.paths,
				changedPathsSummary: summary,
				policyConfigured,
			};
		}

		// Any unmatched path means the rule does not provide an eligible auto-merge candidate.
	}

	return {
		action: "human_review",
		reason: "No auto-merge policy rule matched all changed paths.",
		ruleIndex: null,
		rulePatterns: null,
		ruleExcludes: null,
		matchedPatterns: [],
		changedPathsSummary: {
			excluded: [],
			matched: [],
			unmatched: changedFiles,
		},
		policyConfigured,
	};
}

type RuleMatchSummary = {
	isMatch: boolean;
	matched: string[];
	unmatched: string[];
	excluded: string[];
	missingRequiredPatterns: string[];
};

function evaluateRule(
	rule: PostRunAutoMergeRule,
	changedPaths: string[],
): RuleMatchSummary {
	const includes = splitRulePatterns(rule.paths, rule.excludes);
	const normalizedIncludes = includes.include.map((pattern) =>
		normalizePathPattern(pattern),
	);
	const normalizedExcludes = includes.exclude.map((pattern) =>
		normalizePathPattern(pattern),
	);
	const matchedRequiredPatterns = new Set<string>();
	const requiredPatterns = new Set(
		normalizedIncludes
			.filter((pattern) => pattern.patternType === "include")
			.map((pattern) => pattern.value),
	);
	const summary = {
		excluded: [],
		matched: [],
		unmatched: [],
		missingRequiredPatterns: Array.from(requiredPatterns),
		isMatch: false,
	};

	for (const changedPath of changedPaths) {
		const normalizedPath = changedPath.replace(/^\.\/+/, "");
		let isIncluded = false;
		let isExplicitlyExcluded = false;

		for (const pattern of normalizedIncludes) {
			if (matchGlob(normalizedPath, pattern.value)) {
				isIncluded = true;
				matchedRequiredPatterns.add(pattern.value);
			}
		}

		for (const pattern of normalizedExcludes) {
			if (matchGlob(normalizedPath, pattern.value)) {
				isExplicitlyExcluded = true;
			}
		}

		if (isExplicitlyExcluded) {
			summary.excluded.push(normalizedPath);
			continue;
		}

		if (isIncluded) {
			summary.matched.push(normalizedPath);
			continue;
		}

		summary.unmatched.push(normalizedPath);
	}

	const missingRequiredPatterns = summary.missingRequiredPatterns.filter(
		(pattern) => !matchedRequiredPatterns.has(pattern),
	);
	summary.isMatch =
		missingRequiredPatterns.length === 0 &&
		summary.unmatched.length === 0 &&
		summary.excluded.length === 0 &&
		summary.matched.length > 0;
	summary.missingRequiredPatterns = missingRequiredPatterns;

	return summary;
}

type NormalizedPattern = {
	patternType: "include" | "exclude";
	value: string;
};

function normalizePathPattern(pattern: string): NormalizedPattern {
	const trimmed = pattern.trim();
	return trimmed.startsWith("!")
		? { patternType: "exclude", value: trimmed.slice(1).trim() }
		: { patternType: "include", value: trimmed };
}

function matchGlob(filePath: string, pattern: string): boolean {
	const regexSource = "^" + globToRegex(pattern) + "$";
	return new RegExp(regexSource).test(filePath);
}

type RulePatternGroups = {
	include: string[];
	exclude: string[];
};

function splitRulePatterns(
	includes: string[],
	excludes?: string[],
): RulePatternGroups {
	const includePatterns = includes.filter((pattern) => pattern.trim());
	const normalizedIncludes = includePatterns.map((pattern) => pattern.trim());
	const normalizedExcludes = excludes
		?.map((pattern) =>
			pattern.trim().startsWith("!")
				? pattern.trim().slice(1).trim()
				: pattern.trim(),
		)
		?.filter((pattern) => pattern.length > 0);

	return {
		include: normalizedIncludes,
		exclude: normalizedExcludes ?? [],
	};
}

function globToRegex(pattern: string): string {
	let i = 0;
	let output = "";

	while (i < pattern.length) {
		const char = pattern[i];
		if (char === "*") {
			if (pattern[i + 1] === "*") {
				output += ".*";
				i += 2;
				continue;
			}
			output += "[^/]*";
			i += 1;
			continue;
		}

		if (char === "?") {
			output += "[^/]";
			i += 1;
			continue;
		}

		if ("+^$.()|{}[]\\".includes(char)) {
			output += `\\${char}`;
			i += 1;
			continue;
		}

		output += char;
		i += 1;
	}

	return output;
}
