function splitCsvTopLevel(input: string): string[] {
	const items: string[] = [];
	let inQuotes = false;
	let current = "";
	let escaped = false;

	for (const char of input) {
		if (char === "," && !inQuotes) {
			if (current.trim()) {
				items.push(current.trim());
			}
			current = "";
			continue;
		}

		if (char === '"') {
			if (!escaped) {
				inQuotes = !inQuotes;
			}
			escaped = false;
			current += char;
			continue;
		}

		if (char === "\\") {
			escaped = !escaped;
			current += char;
			continue;
		}

		current += char;
		escaped = false;
	}

	if (current.trim()) {
		items.push(current.trim());
	}

	return items.filter((item) => item.length > 0);
}

